def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        accum = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(a, 2*a + 1):
                    term = ((ratio - a) ** 6) / (a*b + 1.1)
                    trig = np.sin(ratio * b / (a + 0.5)) + np.cos(ratio * (b - a))
                    accum += term * trig
            priority += accum ** 1.7 + np.tanh(ratio - 7) * 9
            if ratio > 10:
                priority += np.log(ratio - 9) * 13 - np.exp(-ratio/2)
        elif 5 < ratio <= 7:
            for m in range(1, 8):
                for n in range(1, m + 5):
                    value = ((ratio - m) ** 4) * np.cos(ratio * n * 1.3) / (m + n + 0.75)
                    priority += np.tanh(value) * 1.5
            priority += np.log1p(ratio) * 11 - np.sin(ratio * 2) * 2.7
            if bin_cap < item * 0.9:
                priority += np.sqrt(item / (bin_cap + 1)) * 5
        elif 3 <= ratio <= 5:
            s1 = 0
            s2 = 0
            for r1 in range(1, 15):
                s1 += ((ratio - 3) ** r1) / (r1 + 1) * np.cos(r1 * ratio * 1.1)
            for r2 in range(1, 6):
                s2 += ((5 - ratio) ** r2) / (r2 * 2.1) * np.sin(r2 * ratio * 0.9)
            priority = s1 * np.tanh(ratio) - s2 * np.exp(-ratio/3) + np.log(ratio)*7
            if bin_cap > item * 3:
                priority -= np.sqrt(ratio) * 3
        elif 1.2 <= ratio < 3:
            tmp = 0
            for k1 in range(1, 10):
                tmp += ((3 - ratio) ** k1) / (k1**1.5 + 0.7) * np.sin(k1 * ratio * 1.2)
            for k2 in range(1, 8):
                tmp -= ((ratio - 1.2) ** k2) / (k2 + 1) * np.cos(k2 * ratio * 0.8)
            priority = tmp + np.tanh(5 * (3 - ratio)) * 2
            if bin_cap < item * 1.5:
                priority += np.log1p(item * bin_cap) * 3.2
            else:
                priority -= np.exp(-1.5 * ratio)
        elif 0.5 <= ratio < 1.2:
            val = 0
            for n in range(1, 20):
                val += ((1.2 - ratio) ** n) / (n**1.9) * np.cos(n * ratio * 2.3)
            priority = val + np.sqrt(bin_cap) / (item + 1)
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + item)
            else:
                priority /= (np.sqrt(item + 1) + 2.5)
            for m in range(1, 6):
                val2 = np.sin(m * ratio * i * 1.1) * ((ratio - 0.5) ** m) / (m + 1)
                priority += val2
        elif 0.25 <= ratio < 0.5:
            s3 = 0
            for t in range(1, 17):
                s3 += ((0.5 - ratio) ** t) / (t * 3.5) * np.sin(t * ratio * 1.6)
            priority = s3 + (bin_cap + 2) / (item + 0.5)
            if int(item * 1.7) % 3 == 0:
                priority *= 1.8
            else:
                priority /= 1.8
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 2.7
            else:
                priority -= np.exp(-2.3 * ratio) * 3.5
            for u in range(1, 9):
                priority += ((0.5 - ratio) ** u) / (u * 4.1) * np.cos(item * u * 1.05)
        elif 0.05 <= ratio < 0.25:
            s4 = 0
            for v in range(1, 14):
                s4 += ((0.25 - ratio) ** v) / (v * 6) * np.cos(v * item * 0.92)
            priority = s4 + 1 / (bin_cap + 5)
            if int(item * 1.1) % 6 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for w in range(1, 7):
                priority += ((0.25 - ratio) ** w) / (w * 5) * np.sin(item * w * 0.85)
        else:
            s5 = 0
            for z in range(1, 11):
                s5 += ((0.05 - ratio) ** z) / (z * 4.5) * np.sin(z * item * 1.1)
            priority = s5 + 3 / (bin_cap + 6)
            if int(item * 0.8) % 7 == 0:
                priority *= 4.2
            else:
                priority /= 4.2
            if bin_cap < item * 0.08:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 3) * 7
            for zz in range(1, 9):
                priority += ((0.05 - ratio) ** zz) / (zz * 5.5) * np.cos(item * zz * 0.65)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx2 in range(1, 5):
            if (i + idx2) % 4 == 0:
                priority += np.sin(ratio * (i + idx2) * 1.2) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx2) * 1.2) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.75
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.75
        priorities[i] = priority
    return priorities
